import{_ as r,o as a,c as e,ah as n}from"./chunks/framework.NjRSjnv-.js";const c=JSON.parse('{"title":"微服务","description":"","frontmatter":{"title":"微服务","order":20},"headers":[],"relativePath":"server/distribute/micro/index.md","filePath":"server/distribute/micro/index.md"}'),l={name:"server/distribute/micro/index.md"};function i(o,t,s,g,h,p){return a(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="微服务治理" tabindex="-1">微服务治理 <a class="header-anchor" href="#微服务治理" aria-label="Permalink to “微服务治理”">​</a></h1><p>微服务架构将单体应用拆分为多个小型服务，每个服务独立开发、部署、扩展。微服务治理是确保微服务架构可运行、可维护、可扩展的一套技术和实践。</p><p>微服务架构引入的核心理由是单数据库的 IO 瓶颈和压力，此外，引入微服务还有其他理由，单体应用的问题：代码库庞大、部署困难、技术栈固定、扩展受限、单点故障。</p><p>微服务的代价：分布式复杂性（服务间通信、数据一致性）、运维复杂度（大量服务需要管理）、调试困难（调用链路长）。</p><p>微服务治理的目标：管理服务数量庞大的系统，保证服务的可用性、性能、一致性。</p><h2 id="微服务治理的核心组件" tabindex="-1">微服务治理的核心组件 <a class="header-anchor" href="#微服务治理的核心组件" aria-label="Permalink to “微服务治理的核心组件”">​</a></h2><p>服务注册与发现：服务如何注册自己的地址，客户端如何发现服务地址。</p><p>配置中心：如何动态管理配置，所有实例能够及时获取最新配置。</p><p>API 网关：统一入口，处理认证、限流、路由、聚合。</p><p>负载均衡：如何将请求分发到多个服务实例。</p><p>缓存架构：提升系统性能、降低数据库负载。</p><h2 id="微服务的健壮性" tabindex="-1">微服务的健壮性 <a class="header-anchor" href="#微服务的健壮性" aria-label="Permalink to “微服务的健壮性”">​</a></h2><p>微服务架构下，服务间的依赖关系复杂，单个服务的故障可能级联扩散，导致整个系统雪崩。健壮性是服务在异常情况下维持核心功能的能力。</p><p>熔断降级：服务故障时快速失败，返回默认值，避免雪崩。</p><p>限流保护：保护服务不被过载请求打垮，确保服务在容量范围内稳定运行。</p><p>舱壁隔离：将资源隔离，避免单个服务的问题影响整个系统。</p><h2 id="微服务的可观测性" tabindex="-1">微服务的可观测性 <a class="header-anchor" href="#微服务的可观测性" aria-label="Permalink to “微服务的可观测性”">​</a></h2><p>微服务架构下，服务数量众多、调用链路复杂，问题定位和性能分析变得困难。可观测性是通过系统的外部输出（日志、指标、链路）来理解系统内部状态的能力。</p><p>监控告警：收集和展示系统的运行指标，及时发现和处理异常。</p><p>链路追踪：记录一个请求经过的所有服务，快速定位故障和性能瓶颈。</p><h2 id="微服务拆分原则" tabindex="-1">微服务拆分原则 <a class="header-anchor" href="#微服务拆分原则" aria-label="Permalink to “微服务拆分原则”">​</a></h2><p>按业务能力拆分：订单服务、库存服务、用户服务。每个服务负责一个完整的业务能力。</p><p>按数据子域拆分：参考领域驱动设计（DDD），每个服务对应一个限界上下文。</p><p>单一职责：每个服务只做一件事，做好一件事。</p><p>独立数据存储：每个服务有自己的数据库，避免共享数据库。</p><p>无状态服务：服务不保存状态，状态存储在外部（Redis、数据库），便于扩展。</p><h2 id="微服务的数据一致性" tabindex="-1">微服务的数据一致性 <a class="header-anchor" href="#微服务的数据一致性" aria-label="Permalink to “微服务的数据一致性”">​</a></h2><p>分布式事务：跨服务的数据一致性难以保证，强一致性方案性能差。</p><p>最终一致性：接受短暂不一致，通过补偿机制保证最终一致。</p><p>幂等性：同一操作执行多次，结果与执行一次相同。</p><p>事件驱动：通过事件总线异步通信，降低服务耦合。</p><p>Saga 模式：长事务拆分为多个本地事务，每个事务有补偿。</p><p>TCC 模式：Try-Confirm-Cancel 三阶段提交。</p><h2 id="微服务的测试与部署" tabindex="-1">微服务的测试与部署 <a class="header-anchor" href="#微服务的测试与部署" aria-label="Permalink to “微服务的测试与部署”">​</a></h2><p>单元测试：测试单个服务的逻辑。</p><p>集成测试：测试服务间的交互。</p><p>契约测试：测试服务接口的兼容性。</p><p>金丝雀发布：先发布到少量实例，验证后全量发布。</p><p>蓝绿部署：维护两套环境，切换流量实现零停机部署。</p><p>滚动发布：逐个替换实例，保证持续可用。</p><p>微服务治理是微服务架构的基石，理解服务治理的组件和模式，有助于设计可维护的微服务系统。</p><h2 id="三高指标" tabindex="-1">三高指标 <a class="header-anchor" href="#三高指标" aria-label="Permalink to “三高指标”">​</a></h2><p>在分布式架构（如你正在搭建的 <strong>K8s + AI 推理集群</strong>）中，“三高”是评价一个系统是否达到“工业级”水准的核心指标。</p><p>简单来说，三高指的是：<strong>高可用 (High Availability)</strong>、<strong>高性能 (High Performance)</strong>、<strong>高并发 (High Concurrency)</strong>。</p><hr><h3 id="_1-高可用-high-availability-ha" tabindex="-1">1. 高可用 (High Availability, HA) <a class="header-anchor" href="#_1-高可用-high-availability-ha" aria-label="Permalink to “1. 高可用 (High Availability, HA)”">​</a></h3><p><strong>探讨核心：系统能不能“不宕机”？</strong></p><p>高可用衡量的是系统面对故障时的生存能力。通常用“几个 9”来表示（如 99.99% 意味着一年停机时间不超过 52 分钟）。</p><ul><li><strong>底层手段</strong>： <ul><li><strong>冗余 (Redundancy)</strong>：不要单点。MySQL 必须有主从，Operator 必须能自动拉起挂掉的 Pod。</li><li><strong>故障转移 (Failover)</strong>：主节点挂了，从节点秒级接管。</li><li><strong>数据备份</strong>：利用 <strong>OSS/S3</strong> 定期存快照。</li></ul></li><li><strong>你的 AI 场景</strong>：如果一个 vLLM 节点显卡掉线了，流量能不能自动切到另一个备用显卡节点？</li></ul><hr><h3 id="_2-高性能-high-performance" tabindex="-1">2. 高性能 (High Performance) <a class="header-anchor" href="#_2-高性能-high-performance" aria-label="Permalink to “2. 高性能 (High Performance)”">​</a></h3><p><strong>探讨核心：系统跑得能不能“足够快”？</strong></p><p>高性能关注的是<strong>响应时间 (Latency)</strong> 和 <strong>吞吐量 (Throughput)</strong>。</p><ul><li><strong>底层手段</strong>： <ul><li><strong>缓存</strong>：用 <strong>Redis</strong> 减少数据库 IO。</li><li><strong>异步</strong>：用 <strong>RocketMQ</strong> 把耗时任务从主流程剥离。</li><li><strong>硬件加速</strong>：对于 C 开发者，你会关注利用 <strong>GPUDirect Storage</strong> 或 <strong>RDMA</strong> 网络减少数据拷贝。</li><li><strong>索引优化</strong>：在 <strong>ElasticSearch</strong> 或 <strong>Milvus</strong> 中通过精密的索引算法加速搜索。</li></ul></li><li><strong>你的 AI 场景</strong>：生成一个 Token 需要多少毫秒（TPOT）？首字返回需要多久（TTFT）？</li></ul><hr><h3 id="_3-高并发-high-concurrency" tabindex="-1">3. 高并发 (High Concurrency) <a class="header-anchor" href="#_3-高并发-high-concurrency" aria-label="Permalink to “3. 高并发 (High Concurrency)”">​</a></h3><p><strong>探讨核心：系统能不能“扛得住多人同时用”？</strong></p><p>高并发衡量的是系统在单位时间内处理请求的能力（QPS/TPS）。</p><ul><li><strong>底层手段</strong>： <ul><li><strong>水平扩展 (Scaling)</strong>：一台服务器扛不住 1000 人，那就通过 <strong>K8s HPA</strong> 自动扩容到 10 台。</li><li><strong>池化技术</strong>：连接池（MySQL）、线程池、甚至 GPU 算力池。</li><li><strong>分库分表</strong>：当 MySQL 单表数据过亿影响并发时，进行拆分。</li></ul></li><li><strong>你的 AI 场景</strong>：当 1000 个用户同时在网页上找你的 Agent 聊天时，系统是依然顺滑，还是直接 OOM 崩溃？</li></ul><hr><h3 id="三者的关系-互相牵制-动态平衡" tabindex="-1">三者的关系：互相牵制，动态平衡 <a class="header-anchor" href="#三者的关系-互相牵制-动态平衡" aria-label="Permalink to “三者的关系：互相牵制，动态平衡”">​</a></h3><p>作为架构师，你需要理解这三者往往是<strong>冲突</strong>的：</p><ul><li>为了<strong>高可用</strong>，你需要多副本数据同步，这会增加延迟，降低<strong>高性能</strong>。</li><li>为了<strong>高并发</strong>，你可能需要引入复杂的缓存逻辑，这增加了系统的复杂性，反而可能降低<strong>高可用</strong>。</li></ul><table tabindex="0"><thead><tr><th style="text-align:left;">指标</th><th style="text-align:left;">解决的问题</th><th style="text-align:left;">核心工具</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高可用</strong></td><td style="text-align:left;">别挂了。</td><td style="text-align:left;">Operator, Keepalived, K8s</td></tr><tr><td style="text-align:left;"><strong>高性能</strong></td><td style="text-align:left;">别慢了。</td><td style="text-align:left;">Redis, C/C++ 优化, SSD</td></tr><tr><td style="text-align:left;"><strong>高并发</strong></td><td style="text-align:left;">别挤爆了。</td><td style="text-align:left;">Nginx, RocketMQ, K8s HPA</td></tr></tbody></table><hr><h3 id="总结建议-结合你的背景" tabindex="-1">总结建议（结合你的背景） <a class="header-anchor" href="#总结建议-结合你的背景" aria-label="Permalink to “总结建议（结合你的背景）”">​</a></h3><p>在你的 <strong>Agent 项目</strong> 中，目前最难调优的其实是 <strong>“高性能”</strong>。</p><ol><li><strong>C/Python 混合优化</strong>：利用 Python 处理业务逻辑，底层推理交给 C++ 优化的 vLLM。</li><li><strong>流量调度</strong>：使用我们刚才聊过的<strong>限流降级</strong>，当并发超过“高并发”阈值时，牺牲一部分用户的体验来换取整体的“高可用”。</li></ol><p><strong>既然了解了三高的定义，你想看看在 K8s 环境下，如何利用 Prometheus 监控指标来实时定义你系统的“三高”基准线吗？</strong></p>',69)])])}const b=r(l,[["render",i]]);export{c as __pageData,b as default};
